// Verifies the fix for the getDisplayData crop-mode OOM. Loads the synthetic
// 10M-point fixture (generated by scripts/make-big-xyz.mjs), selects the
// cloud, then clicks the Crop tool button. Samples heap rapidly during the
// post-click window to capture peak transient allocation — that's where the
// JS-array intermediate would have ballooned pre-fix.
//
// Pass criterion: peak heap during the crop-click window stays well under
// the 4 GB V8 old-space limit. Pre-fix on this fixture peaks around the
// JS-boxed-double intermediate; post-fix the peak is roughly the
// destination Float32Array size only.

import { _electron } from '@playwright/test';
import { existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(__dirname, '..');
const FIXTURE = join(repoRoot, 'tmp', 'big.xyz');

if (!existsSync(FIXTURE)) {
  console.error(`Missing ${FIXTURE}. Run \`N=10000000 node scripts/make-big-xyz.mjs\` first.`);
  process.exit(1);
}
if (!existsSync(join(repoRoot, 'dist-main', 'main.js'))) {
  console.error('Run `npm run build` first.');
  process.exit(1);
}

const app = await _electron.launch({
  args: ['.'],
  cwd: repoRoot,
  timeout: 60_000,
  env: { ...process.env, PHYTOGRAPH_E2E: '1' },
});
const page = await app.firstWindow();

// Wait for backend.
{
  const start = Date.now();
  while (Date.now() - start < 120_000) {
    try {
      const res = await fetch('http://127.0.0.1:8008/version', { signal: AbortSignal.timeout(2_000) });
      if (res.ok) break;
    } catch {}
    await new Promise((r) => setTimeout(r, 1_000));
  }
}

const cdp = await page.context().newCDPSession(page);
await cdp.send('HeapProfiler.enable');

async function gc() {
  await cdp.send('HeapProfiler.collectGarbage');
  await cdp.send('HeapProfiler.collectGarbage');
}
async function rawHeap() {
  // No GC — we want to see transient peaks.
  return (await cdp.send('Runtime.getHeapUsage')).usedSize;
}
async function settledHeap() {
  await gc();
  return (await cdp.send('Runtime.getHeapUsage')).usedSize;
}
const fmt = (b) => `${(b / 1024 / 1024).toFixed(1)} MB`;

await page.getByTestId('nav-viewer').click();

// Import big.xyz.
console.log('Importing 10M-point fixture (this can take 30-60s on big files)...');
await page.getByTestId('import-menu-button').click();
const [chooser] = await Promise.all([
  page.waitForEvent('filechooser'),
  page.getByTestId('import-menu-auto').click(),
]);
await chooser.setFiles(FIXTURE);
const row = page.locator('[data-testid="scan-row"][data-scan-name="big.xyz"]');
await row.waitFor({ timeout: 180_000 });
console.log('cloud loaded.');

// Let things settle, then take a baseline.
await page.waitForTimeout(2000);
const baseline = await settledHeap();
console.log(`baseline (cloud loaded, after GC): ${fmt(baseline)}`);

// Select the cloud (required for the Crop tool to be enabled).
await row.click();
await page.waitForTimeout(500);

// Find the Crop tool button by its title.
const cropButton = page.locator('button[title="Crop"]');
await cropButton.waitFor({ timeout: 5_000 });

// Sample heap continuously for the duration of the crop click + render.
let stop = false;
let peak = baseline;
const samples = [];
const sampler = (async () => {
  const t0 = Date.now();
  while (!stop) {
    const used = await rawHeap();
    if (used > peak) peak = used;
    samples.push({ t: (Date.now() - t0) / 1000, used });
    await new Promise((r) => setTimeout(r, 40));
  }
})();

console.log('Clicking Crop...');
const clickAt = Date.now();
await cropButton.click();
// Let the crop-preview path run plenty of renders.
await page.waitForTimeout(6_000);
stop = true;
await sampler;

const settled = await settledHeap();
console.log('\nheap samples (raw, no GC):');
for (const s of samples) {
  if (s.t * 1000 < (Date.now() - clickAt) + 200) {
    console.log(`  t=${s.t.toFixed(2)}s  ${fmt(s.used)}`);
  }
}
console.log(`\npeak during click window: ${fmt(peak)}`);
console.log(`settled after GC:         ${fmt(settled)}`);
console.log(`peak Δ vs baseline:       ${fmt(peak - baseline)}`);

const peakGB = peak / 1024 / 1024 / 1024;
if (peakGB > 2.5) {
  console.error(`\nFAIL: peak heap > 2.5 GB on a 10M-point fixture — the JS-array intermediate path is likely still present.`);
  await app.close();
  process.exit(1);
}
console.log('\nPASS: peak heap stayed well under V8 old-space limit.');

await app.close();
